#include <bits/stdc++.h>
using namespace std;

const int N=15,mod=1e9+7;

int n,a[N],sum,cw,ct,b[N];
map<long long,int> mp;

int dfs(int x,int y){
	if(x==n)
		return 1;
	if((n-y+1)*3<a[x])
		return 0;
	if(y>n){
		for(int i=x+1;i<=n;i++)
			b[i-x]=a[i];
		sort(b+1,b+n-x+1);
		long long tmp=0;
		for(int i=1;i<=n-x;i++)
			tmp=tmp*29+b[i]+1;
		if(mp.find(tmp)!=mp.end())
			return mp[tmp];
		else
			return mp[tmp]=dfs(x+1,x+2);
	}
	int res=0;
	if(cw && a[x]>=3){
		cw--,a[x]-=3;
		res=(res+dfs(x,y+1))%mod;
		cw++,a[x]+=3;
	}
	if(cw && a[y]>=3){
		cw--,a[y]-=3;
		res=(res+dfs(x,y+1))%mod;
		cw++,a[y]+=3;
	}
	if(ct && a[x] && a[y]){
		ct--,a[x]--,a[y]--;
		res=(res+dfs(x,y+1))%mod;
		ct++,a[x]++,a[y]++;
	}
	return res;
}

int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		sum+=a[i];
	}
	cw=sum-2*n*(n-1)/2,ct=n*(n-1)/2-cw;
	printf("%d",dfs(1,2));
	return 0;
}
